"""Email address validation module."""

import re

VALID_TLDS = {
    "com", "org", "net", "edu", "gov", "mil",
    "io", "co", "dev", "app", "ai", "cloud",
}

_LOCAL_PART_RE = re.compile(r"^[A-Za-z0-9.!#$%&'*+/=?^_`{|}~-]+$")
_DOMAIN_LABEL_RE = re.compile(r"^[A-Za-z0-9-]+$")
_TLD_RE = re.compile(r"^[A-Za-z]{2,63}$")


def is_valid_email(email: str) -> bool:
    """
    Check if an email address is valid.

    Rules:
    - Must contain exactly one @ symbol
    - Local part must be 1-64 chars
    - Domain must have at least one dot
    - TLD must be alphabetic and 2-63 chars
    """
    if not email or "@" not in email:
        return False

    parts = email.split("@")
    if len(parts) != 2:
        return False

    local, domain = parts
    if len(local) < 1 or len(local) > 64:
        return False

    if not _LOCAL_PART_RE.fullmatch(local):
        return False

    if "." not in domain:
        return False

    labels = domain.split(".")
    if any(not label for label in labels):
        return False

    for label in labels[:-1]:
        if not _DOMAIN_LABEL_RE.fullmatch(label):
            return False
        if label.startswith("-") or label.endswith("-"):
            return False

    tld = labels[-1].lower()
    if not _TLD_RE.fullmatch(tld):
        return False

    return True

import pytest

from shopping_cart import ShoppingCart


@pytest.fixture
def cart():
    return ShoppingCart()


def test_add_item_adds_new_item_and_updates_total(cart):
    cart.add_item("Laptop", 999.99, 1)

    assert "Laptop" in cart.items
    assert cart.items["Laptop"] == {"price": 999.99, "quantity": 1}
    assert cart.calculate_total() == 999.99


def test_add_item_duplicate_increases_quantity_without_changing_price(cart):
    cart.add_item("Book", 12.50, 1)
    cart.add_item("Book", 12.50, 3)

    assert len(cart.items) == 1
    assert cart.items["Book"]["quantity"] == 4
    assert cart.items["Book"]["price"] == 12.50
    assert cart.calculate_total() == 50.0


@pytest.mark.parametrize(
    "name, price, quantity, message",
    [
        ("Widget", -1.0, 1, "Price cannot be negative"),
        ("Widget", 5.0, 0, "Quantity must be positive"),
        ("", 5.0, 1, "Item name cannot be empty"),
        ("   ", 5.0, 1, "Item name cannot be empty"),
    ],
)
def test_add_item_rejects_invalid_inputs(cart, name, price, quantity, message):
    with pytest.raises(ValueError, match=message):
        cart.add_item(name, price, quantity)


def test_remove_item_deletes_existing_item_and_updates_total(cart):
    cart.add_item("Pen", 1.5, 2)
    cart.add_item("Notebook", 4.0, 1)

    cart.remove_item("Pen")

    assert "Pen" not in cart.items
    assert "Notebook" in cart.items
    assert cart.calculate_total() == 4.0


def test_remove_item_missing_raises_keyerror(cart):
    with pytest.raises(KeyError, match="Item 'Missing' not found in cart"):
        cart.remove_item("Missing")


def test_calculate_total_returns_zero_for_empty_cart(cart):
    assert cart.calculate_total() == 0


def test_calculate_total_sums_multiple_line_items(cart):
    cart.add_item("Apple", 1.25, 4)
    cart.add_item("Milk", 3.5, 2)

    assert cart.calculate_total() == 12.0


